#!/usr/bin/env bash

set -euo pipefail

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"

TAILS_WORD='ta'"'"'ils'
WORD_B='a'"'"'i'

FORBIDDEN_REGEX=(
    "(^|[^[:alnum:]_])${TAILS_WORD}([^[:alnum:]_]|$)"
    "${TAILS_WORD}\\.net"
    "${TAILS_WORD}-stable"
    "generated by[[:space:]]+${WORD_B}"
    "${WORD_B}-assisted"
    "built with[[:space:]]+${WORD_B}"
)

TARGETS=(
    "${ROOT_DIR}/README.md"
    "${ROOT_DIR}/build"
    "${ROOT_DIR}/config"
    "${ROOT_DIR}/apps"
    "${ROOT_DIR}/tests"
    "${ROOT_DIR}/docs"
)

for pattern in "${FORBIDDEN_REGEX[@]}"; do
    if grep -RInE -i --binary-files=without-match --exclude-dir=__pycache__ --exclude="*.pyc" --exclude="verify-no-leaks.sh" -- "${pattern}" "${TARGETS[@]}" >/dev/null; then
        echo "forbidden string found (pattern): ${pattern}" >&2
        grep -RInE -i --binary-files=without-match --exclude-dir=__pycache__ --exclude="*.pyc" --exclude="verify-no-leaks.sh" -- "${pattern}" "${TARGETS[@]}" >&2
        exit 1
    fi
done

echo "No forbidden naming leaks found."
